SELECT i.name AS assignee_name, u.username AS user_username
FROM inventors i
JOIN user_accounts u ON i.name = u.username;

SELECT pubdate, pubnum, title, abstract
FROM patent_applications
WHERE appno = 1;

SELECT COUNT(*)
FROM patent_applications
WHERE patent_type = 'Utility';

SELECT title, abstract
FROM patent_applications
WHERE patent_type = 'Utility' AND filedate > '2008-12-31';

SELECT strftime('%Y', pubdate) AS pub_year, COUNT(*) AS app_count
FROM patent_applications
GROUP BY pub_year;

SELECT DISTINCT inv.name AS inventor_name, inv.email AS inventor_email
FROM inventors inv
JOIN inventor_applications ia ON inv.inv_id = ia.inv_id;

SELECT appno, COUNT(inv_id) AS inventor_count
FROM inventor_applications
GROUP BY appno;

SELECT name, expertise 
FROM inventors 
WHERE expertise LIKE '%Materials Science and Nanotechnology%';
